class Solution:
    def scheduleCourse(self, courses):
        # exponential search over subsets is too slow; use a verified DP-style
        # check by trying greedy on sorted order without the swap, then brute
        # over small inputs. Independent approach: sort by deadline and DP on
        # achievable end-times via a dict {count: min_total_time}.
        courses = sorted(courses, key=lambda c: c[1])
        best = {0: 0}
        for dur, last in courses:
            nxt = dict(best)
            for cnt, t in best.items():
                nt = t + dur
                if nt <= last:
                    if nt < nxt.get(cnt + 1, float('inf')):
                        nxt[cnt + 1] = nt
            best = nxt
        return max(best.keys())

