import heapq
class Solution:
    def scheduleCourse(self, courses):
        courses.sort(key=lambda c: c[1])
        heap = []
        total = 0
        for dur, last in courses:
            heapq.heappush(heap, -dur)
            total += dur
            if total > last:
                total += heapq.heappop(heap)
        return len(heap)

